sys_script.script:
(function executeRule(current, previous /*null when async*/) {

    // Get the Date Sold On (assuming field name: u_date_sold_on - replace with actual field name)
    var soldOn = current.date_sold_on;  // This is a GlideDate field (date only)

    // Get the Warranty Period in months (assuming integer field: u_warranty_period_months - replace with actual)
    var months = parseInt(current.warranty_period_months, 10);

    // Only calculate if both fields have valid values
    if (!soldOn || isNaN(months) || months <= 0) {
        current.warranty_expiring_at = null;  // Clear if invalid (optional)
        return;
    }

    // Convert GlideDate to GlideDateTime for month addition
    var gdt = new GlideDateTime();
    gdt.setValue(soldOn.getValue());  // Preserve the date part

    // Add the months (use addMonthsLocalTime to respect system time zone for date calculations)
    gdt.addMonthsLocalTime(months);

    // Typically, warranty expires at the end of the day on the calculated date.
    // To make it end-of-day: set time to 23:59:59 (if target field is Date/Time)
    // If target field is Date only, skip time setting.
    gdt.setValue(gdt.getDate().getValue() + " 23:59:59");

    // Set the Warranty Expiring At field 
    current.warranty_expiring_at = gdt;

    // No need for current.update() in a Before BR - changes are applied directly

})(current, previous);
